22→        throw {status: 404, message: 'user not found'};
23→    }
24→
25→    const user = users[0];
26→
27→    const followerCountPromise = supabase
28→        .from('follows')
29→        .select('*', {count: 'exact', head: true})
30→        .eq('following_id', user.id);
31→
32→    const followingCountPromise = supabase
33→        .from('follows')
34→        .select('*', {count: 'exact', head: true})
35→        .eq('follower_id', user.id);
36→
37→    const [followerCountResult, followingCountResult] = await Promise.all([
