112→export const getStoriesService = async (limit, before, status, tag, userId) => {
113→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 10, 1), 20);
114→
115→    let query = supabase
116→        .from('stories')
117→        .select(STORY_SELECT_COLUMNS)
118→        .eq('privacy', 'public')
119→        .order('created_at', { ascending: false })
120→        .limit(parsedLimit + 1);
121→
122→    if (before) {
123→        query = query.lt('created_at', before);
124→    }
125→    if (status && ['ongoing', 'completed', 'hiatus'].includes(status)) {
126→        query = query.eq('status', status);
127→    }
128→    if (tag) {
129→        query = query.contains('tags', [tag]);
130→    }
131→
132→    const { data, error } = await query;
133→
134→    if (error) {
135→        console.error('supabase error fetching stories:', error.message);
136→        throw { status: 500, error: 'failed to fetch stories' };
137→    }
138→
139→    if (!data || data.length === 0) {
140→        return { data: [], hasMore: false };
141→    }
142→
143→    // Batch-fetch author profiles
144→    const authorMap = await fetchAuthorProfiles(data.map(s => s.author_id));
145→
146→    // Fetch user interaction flags if logged in
147→    let userVotedSet = new Set();
148→    let userLibrarySet = new Set();
149→
150→    if (userId) {
151→        const storyIds = data.map(s => s.id);
152→        const [votes, library] = await Promise.all([
153→            supabase.from('story_votes').select('story_id').in('story_id', storyIds).eq('user_id', userId),
154→            supabase.from('story_library').select('story_id').in('story_id', storyIds).eq('user_id', userId),
155→        ]);
156→
157→        if (votes.data) userVotedSet = new Set(votes.data.map(v => v.story_id));
158→        if (library.data) userLibrarySet = new Set(library.data.map(l => l.story_id));
159→    }
160→
161→    const formatted = data.map(story => ({
162→        ...stripEmbedding(story),
163→        users: authorMap[story.author_id] || null,
164→        has_voted: userVotedSet.has(story.id),
165→        in_library: userLibrarySet.has(story.id),
166→    }));
167→
168→    const hasMore = data.length > parsedLimit;
169→    const sliced = hasMore ? formatted.slice(0, parsedLimit) : formatted;
170→
171→    return { data: sliced, hasMore };
172→};
