  3→/**
  4→ * Extract word count from Lexical JSON content.
  5→ * Walks all text nodes and counts whitespace-separated words.
  6→ */
  7→const extractWordCount = (content) => {
  8→    if (!content) return 0;
  9→    let parsed = content;
 10→    if (typeof content === 'string') {
 11→        try { parsed = JSON.parse(content); } catch { return 0; }
 12→    }
 13→
 14→    let text = '';
 15→    const walk = (node) => {
 16→        if (node.text) text += node.text + ' ';
 17→        if (node.children) node.children.forEach(walk);
 18→    };
 19→    if (parsed.root) walk(parsed.root);
 20→    else walk(parsed);
 21→
 22→    return text.trim() ? text.trim().split(/\s+/).length : 0;
 23→};
