 179→    const host = forwardedHost || req.get('host') || '';
 180→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 181→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 182→        ? forwardedProto
 183→        : requestProtocol === 'http' || requestProtocol === 'https'
 184→            ? requestProtocol
