 210→const imageFromNodeLike = (nodeLike) => {
 211→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 212→
 213→    const src = pickFirstNonEmptyString(
 214→        nodeLike.src,
 215→        nodeLike.url,
 216→        nodeLike.image_url,
 217→        nodeLike.imageUrl,
 218→        nodeLike?.payload?.src,
 219→        nodeLike?.data?.src
 220→    );
 221→    if (!src) return null;
