536→    if(Array.isArray(writingInterests)){
537→        payload.writing_interests = writingInterests.filter(i => typeof i === 'string').slice(0, 16);
538→    }
539→    if(writingGoal && typeof writingGoal === 'string'){
540→        payload.writing_goal = writingGoal;
541→    }
542→
543→    if(Object.keys(payload).length === 0){
544→        throw {status: 400, error: 'no valid fields to update'};
545→    }
546→
547→    const {error} = await supabase
548→        .from('users')
549→        .update(payload)
550→        .eq('id', userId);
551→
552→    if(error){
553→        console.error('supabase error updating interests:', error.message);
554→        throw {status: 500, error: 'failed to update interests'};
555→    }
556→
557→    // Await embedding so it's in the DB before response (feed refetch needs it)
558→    if(Array.isArray(writingInterests) && writingInterests.length > 0){
559→        await updateUserInterestsEmbedding(userId, writingInterests);
560→    }
561→
562→    return true;
563→}
