 3→/**
 4→ * Get Monday 00:00 UTC for the current week.
 5→ */
 6→function getCurrentWeekMonday() {
 7→    const now = new Date();
 8→    const day = now.getUTCDay(); // 0=Sun, 1=Mon, ...
 9→    const diff = day === 0 ? 6 : day - 1; // days since Monday
10→    const monday = new Date(Date.UTC(
11→        now.getUTCFullYear(),
12→        now.getUTCMonth(),
13→        now.getUTCDate() - diff,
14→        0, 0, 0, 0
15→    ));
16→    return monday.toISOString();
17→}
18→
19→export const getWeeklyRecapService = async (userId) => {
20→    const weekStart = getCurrentWeekMonday();
21→
22→    const { data, error } = await supabase.rpc('get_weekly_recap', {
23→        p_user_id: userId,
24→        p_week_start: weekStart,
25→    });
26→
27→    if (error) {
28→        console.error('weekly recap RPC error:', error);
29→        throw new Error(error.message || 'Failed to get weekly recap');
30→    }
31→
32→    return data;
33→};
