100→                        <span className="dashboard-briefing-date">{formatDate()}</span>
101→                        {streakCount > 0 && <StreakBadge count={streakCount} size={14} />}
102→                    </div>
103→                    {hasRecap && (
104→                        <button
105→                            className={`dashboard-briefing-toggle ${recapCollapsed ? 'is-collapsed' : ''}`}
106→                            onClick={handleToggleRecap}
107→                            title={recapCollapsed ? 'Show stats' : 'Hide stats'}
108→                        >
109→                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
110→                                <path d="M6 9L12 15L18 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
111→                            </svg>
112→                        </button>
113→                    )}
114→                </div>
