19→const toPreviewText = (value, maxLength = 160) => {
20→  const normalized = String(value ?? "").replace(/\s+/g, " ").trim();
21→  if (!normalized) return "";
22→  if (normalized.length <= maxLength) return normalized;
23→  return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
24→};
