43→    ensureMeta("post-seo-og-description", "property", "og:description", description);
44→    ensureMeta("post-seo-og-image", "property", "og:image", ogImage);
45→    if (postUrl) {
46→      ensureMeta("post-seo-og-url", "property", "og:url", postUrl);
47→    }
48→
49→    ensureMeta("post-seo-twitter-title", "name", "twitter:title", postData.title);
50→    ensureMeta("post-seo-twitter-description", "name", "twitter:description", description);
51→    ensureMeta("post-seo-twitter-image", "name", "twitter:image", ogImage);
52→
53→    if (postUrl) {
54→      ensureLink("post-seo-canonical", "canonical", postUrl);
55→    }
56→
57→    const articleLd = {
58→      "@context": "https://schema.org",
59→      "@type": "Article",
60→      headline: postData.title,
61→      description: description,
62→      datePublished: postData.created_at || undefined,
63→      author: {
64→        "@type": "Person",
65→        name: postData.name || "Unknown",
66→      },
67→      publisher: {
68→        "@type": "Organization",
69→        name: "Iskryb",
70→        url: SITE_URL,
