  1→import express from 'express';
  2→import supabase from '../services/supabase.js';
  3→import { SITE_URL, makePostUrl } from '../utils/urlUtils.js';
  4→
  5→const sitemapRouter = express.Router();
  6→
  7→const CACHE_MAX_AGE_SECONDS = 3600; // 1 hour
  8→const API_BASE_URL = 'https://iskrib-v3-server-production.up.railway.app';
  9→
 10→const escXml = (str) => String(str)
 11→    .replace(/&/g, '&amp;')
 12→    .replace(/</g, '&lt;')
 13→    .replace(/>/g, '&gt;')
 14→    .replace(/"/g, '&quot;')
 15→    .replace(/'/g, '&apos;');
 16→
 17→// ── GET /api/sitemap-posts.xml ──
 18→sitemapRouter.get('/sitemap-posts.xml', async (_req, res) => {
 19→    try {
 20→        const { data: posts, error } = await supabase
 21→            .from('journals')
 22→            .select('id, title, created_at')
 23→            .eq('privacy', 'public')
 24→            .order('created_at', { ascending: false });
 25→
 26→        if (error) {
 27→            console.error('sitemap-posts query error:', error.message);
 28→            return res.status(500).send('internal error');
 29→        }
 30→
 31→        const urls = (posts || []).map((post) => {
 32→            const loc = escXml(makePostUrl(post.id, post.title || ''));
 33→            const lastmod = post.created_at
 34→                ? new Date(post.created_at).toISOString().split('T')[0]
 35→                : '';
 36→            return `  <url>\n    <loc>${loc}</loc>${lastmod ? `\n    <lastmod>${lastmod}</lastmod>` : ''}\n    <changefreq>monthly</changefreq>\n    <priority>0.7</priority>\n  </url>`;
 37→        });
 38→
 39→        const xml = `<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${urls.join('\n')}\n</urlset>`;
 40→
 41→        res.set('Content-Type', 'application/xml; charset=utf-8');
 42→        res.set('Cache-Control', `public, max-age=${CACHE_MAX_AGE_SECONDS}`);
 43→        return res.send(xml);
 44→    } catch (err) {
 45→        console.error('sitemap-posts error:', err?.message || err);
 46→        return res.status(500).send('internal error');
 47→    }
 48→});
 49→
 50→// ── GET /api/sitemap-profiles.xml ──
 51→sitemapRouter.get('/sitemap-profiles.xml', async (_req, res) => {
 52→    try {
 53→        const { data: users, error } = await supabase
 54→            .from('users')
 55→            .select('id, username')
 56→            .not('username', 'is', null);
 57→
 58→        if (error) {
 59→            console.error('sitemap-profiles query error:', error.message);
 60→            return res.status(500).send('internal error');
 61→        }
 62→
 63→        const urls = (users || []).map((user) => {
 64→            const loc = escXml(`${SITE_URL}/u/${user.username}`);
 65→            return `  <url>\n    <loc>${loc}</loc>\n    <changefreq>weekly</changefreq>\n    <priority>0.6</priority>\n  </url>`;
 66→        });
 67→
 68→        const xml = `<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${urls.join('\n')}\n</urlset>`;
 69→
 70→        res.set('Content-Type', 'application/xml; charset=utf-8');
 71→        res.set('Cache-Control', `public, max-age=${CACHE_MAX_AGE_SECONDS}`);
 72→        return res.send(xml);
 73→    } catch (err) {
 74→        console.error('sitemap-profiles error:', err?.message || err);
 75→        return res.status(500).send('internal error');
 76→    }
 77→});
 78→
 79→// ── GET /api/sitemap-index.xml ──
 80→sitemapRouter.get('/sitemap-index.xml', (_req, res) => {
 81→    const xml = `<?xml version="1.0" encoding="UTF-8"?>
 82→<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
 83→  <sitemap>
 84→    <loc>${escXml(`${SITE_URL}/sitemap.xml`)}</loc>
 85→  </sitemap>
 86→  <sitemap>
 87→    <loc>${escXml(`${SITE_URL}/api/sitemap-posts.xml`)}</loc>
 88→  </sitemap>
 89→  <sitemap>
 90→    <loc>${escXml(`${SITE_URL}/api/sitemap-profiles.xml`)}</loc>
 91→  </sitemap>
 92→</sitemapindex>`;
 93→
 94→    res.set('Content-Type', 'application/xml; charset=utf-8');
 95→    res.set('Cache-Control', `public, max-age=${CACHE_MAX_AGE_SECONDS}`);
 96→    return res.send(xml);
 97→});
 98→
 99→export default sitemapRouter;
