1331→export const searchJournalsService = async(query, limit, userId) => {
1332→    const normalizedQuery = normalizeSearchQuery(query);
1333→    if(!normalizedQuery || normalizedQuery.length < SEARCH_QUERY_MIN_LENGTH){
1334→        throw {status: 400, error: `query should be at least ${SEARCH_QUERY_MIN_LENGTH} characters`};
1335→    }
1336→
1337→    if(isNaN(limit) || limit < 1 || limit > SEARCH_LIMIT_MAX){
1338→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1339→    }
1340→
1341→    const parsedLimit = parseInt(limit);
1342→    const fetchLimit = Math.min(parsedLimit * 3, 60);
1343→
1344→    const selectColumns = JOURNAL_WITH_COUNTS_SELECT;
1345→
1346→    // Prefer semantic retrieval. If pgvector RPC is unavailable or errors,
1347→    // fallback to keyword search so endpoint still returns useful data.
1348→    try {
1349→        const queryEmbedding = await GenerateEmbeddings(normalizedQuery, '');
1350→
1351→        if(Array.isArray(queryEmbedding) && queryEmbedding.length > 0){
1352→            const {data: matches, error: matchError} = await supabase.rpc('match_public_journals', {
1353→                query_embedding: queryEmbedding,
1354→                match_count: fetchLimit,
1355→                similarity_threshold: 0.35
1356→            });
1357→
1358→            if(matchError){
1359→                console.error('semantic search rpc error:', matchError.message);
1360→            } else if(Array.isArray(matches) && matches.length > 0){
1361→                const matchIds = matches.map((row) => row.id);
1362→                const similarityMap = new Map(matches.map((row) => [row.id, row.similarity]));
1363→
1364→                const {data: journals, error: errorJournals} = await supabase
1365→                    .from('journals')
1366→                    .select(selectColumns)
