1369→
1370→                if(errorJournals){
1371→                    console.error('supabase error while fetching semantic search journals:', errorJournals.message);
1372→                    throw {status: 500, error: 'supabase error while fetching semantic search journals'};
1373→                }
1374→
1375→                const journalById = new Map((journals || []).map((journal) => [journal.id, journal]));
1376→                const orderedSemantic = matchIds
1377→                    .map((id) => journalById.get(id))
1378→                    .filter(Boolean)
1379→                    .map((journal) => ({
1380→                        ...journal,
1381→                        similarity: similarityMap.get(journal.id) || null
1382→                    }));
1383→
1384→                const withInteraction = await attachUserInteractionFlags(orderedSemantic, userId);
1385→                const hasMore = withInteraction.length > parsedLimit;
1386→
1387→                return {
1388→                    data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1389→                    hasMore: hasMore,
1390→                    mode: 'semantic'
1391→                };
1392→            }
1393→        }
1394→    } catch (error) {
1395→        console.error('semantic embedding/search fallback error:', error?.message || error);
1396→    }
1397→
1398→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
