164→// ─── Helpers ───
165→
166→function getUTCDateString() {
167→    const now = new Date();
168→    return now.toISOString().split('T')[0]; // 'YYYY-MM-DD'
169→}
170→
171→function daysBetween(dateStrA, dateStrB) {
172→    const a = new Date(dateStrA + 'T00:00:00Z');
173→    const b = new Date(dateStrB + 'T00:00:00Z');
174→    return Math.round((b - a) / (1000 * 60 * 60 * 24));
175→}
