201→    if (!chapterId) {
202→        throw { status: 400, error: 'chapterId is required' };
203→    }
204→
205→    let query = supabase
206→        .from('story_comments')
207→        .select(`*, users(id, name, image_url, username, badge)`)
208→        .eq('chapter_id', chapterId)
209→        .is('parent_id', null)
210→        .order('created_at', { ascending: true });
211→
212→    if (paragraphIndex !== undefined && paragraphIndex !== null) {
213→        query = query.eq('paragraph_index', parseInt(paragraphIndex));
214→    }
215→
216→    const { data: comments, error } = await query;
217→
218→    if (error) {
219→        console.error('supabase error fetching comments:', error.message);
220→        throw { status: 500, error: 'failed to fetch comments' };
221→    }
222→
223→    // Fetch replies for all top-level comments
224→    if (comments && comments.length > 0) {
225→        const commentIds = comments.map(c => c.id);
226→        const { data: replies, error: replyError } = await supabase
227→            .from('story_comments')
228→            .select(`*, users(id, name, image_url, username, badge)`)
229→            .in('parent_id', commentIds)
230→            .order('created_at', { ascending: true });
231→
232→        if (!replyError && replies) {
233→            const replyMap = {};
234→            replies.forEach(r => {
235→                if (!replyMap[r.parent_id]) replyMap[r.parent_id] = [];
236→                replyMap[r.parent_id].push(r);
237→            });
238→            comments.forEach(c => {
239→                c.replies = replyMap[c.id] || [];
240→            });
241→        }
242→    }
243→
244→    return comments || [];
245→};
